import{_ as t,o as r,c as n,ae as a}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Connected Troubleshooting","description":"","frontmatter":{"title":"Connected Troubleshooting","slug":"connected-troubleshooting"},"headers":[],"relativePath":"developer-hub/connected-troubleshooting.md","filePath":"developer-hub/connected-troubleshooting.md"}'),i={name:"developer-hub/connected-troubleshooting.md"};function o(d,e,s,c,l,h){return r(),n("div",null,[...e[0]||(e[0]=[a('<h3 id="minimum-requirements" tabindex="-1">Minimum Requirements <a class="header-anchor" href="#minimum-requirements" aria-label="Permalink to &quot;Minimum Requirements&quot;">​</a></h3><ul><li>The Branch Connected SDK requires native browser Javascript and has only been tested in Tizen and WebOS with sessionStorage capability. No 3rd party libraries are needed to make use of the SDK as is it 100% native Javascript.</li></ul><table tabindex="0"><thead><tr><th>Tizen</th><th>WebOS</th></tr></thead><tbody><tr><td>2.3</td><td>6.0</td></tr></tbody></table><h3 id="branch-init-options" tabindex="-1">Branch init Options <a class="header-anchor" href="#branch-init-options" aria-label="Permalink to &quot;Branch init Options&quot;">​</a></h3><ul><li>Properties which you can pass within <code>branch.initSession()</code></li><li>Used for <a href="./connected-advanced-features.html#section-initialize-branch-features">Initialize Branch features</a></li></ul><table tabindex="0"><thead><tr><th>Key</th><th>Value</th><th>Type</th><th>Required</th></tr></thead><tbody><tr><td>advertising_ids</td><td>The current devices advertising id declared by the brand&#39;s corresponding key. Please refer to <a href="./connected-basic-integration.html#advertising-id-index">Connected Basic Integration</a> for more the key index.</td><td><code>{string:string}</code></td><td><strong>Y</strong> for Ad Network Attribution <strong>N</strong> for Web Based Attribution</td></tr><tr><td>branch_match_id</td><td>The current user&#39;s browser-fingerprint-id. The value of this parameter should be the same as the value of ?<em>branch_match_id (automatically appended by Branch after a link click). _Only necessary if ?_branch_match_id is lost due to multiple redirects in your flow</em>.</td><td><code>string</code></td><td>N</td></tr><tr><td>retries</td><td>default: 2</td><td><code>number</code></td><td>N</td></tr><tr><td>retry_delay</td><td>expressed in milliseconds default: 200ms</td><td><code>number</code></td><td>N</td></tr><tr><td>timeout</td><td>expressed in milliseconds default:5000ms</td><td><code>number</code></td><td>N</td></tr><tr><td>tracking_disabled</td><td>default: false</td><td><code>boolean</code></td><td>N</td></tr><tr><td>enableLogging</td><td>default: false</td><td>`boolean</td><td>N</td></tr></tbody></table><h3 id="no-access-control-error" tabindex="-1">No Access-Control Error <a class="header-anchor" href="#no-access-control-error" aria-label="Permalink to &quot;No Access-Control Error&quot;">​</a></h3><ul><li>Make sure the Branch key is the same within the deep link and app</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>XMLHttpRequest cannot load https://api2.branch.io/v1/open. No &#39;Access-Control-Allow-Origin&#39; header is present on the requested resource. Origin &#39;null&#39; is therefore not allowed access. The response had HTTP status code 400.</span></span></code></pre></div><h3 id="browser-fingerprint-id" tabindex="-1">Browser Fingerprint ID <a class="header-anchor" href="#browser-fingerprint-id" aria-label="Permalink to &quot;Browser Fingerprint ID&quot;">​</a></h3><ul><li>In case you need to access your user&#39;s Browser Fingerprint ID for user deletion, use the function below.</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.getBrowserFingerprintId(function(err, data) { console.log(data); });</span></span></code></pre></div>',12)])])}const b=t(i,[["render",o]]);export{p as __pageData,b as default};
